// Classify and extract fields from an incoming Gmail message.
// This is the inlined version of lib/parseEmail.js — the canonical source
// with unit tests lives in the repo. Keep the two in sync.

const AUTOMATION_EMAIL = ($env.AUTOMATION_EMAIL || 'automation@hellolunajoy.com').toLowerCase();
const INTERNAL_DOMAINS = ($env.INTERNAL_DOMAINS || 'hellolunajoy.com,lunajoy.com')
  .split(',').map(s => s.trim().replace(/^@/, '').toLowerCase()).filter(Boolean);
const SKIP_SENDER_PATTERNS = ($env.SKIP_SENDER_PATTERNS ||
  '^noreply@,^no-reply@,^mailer-daemon@,^postmaster@,^bounces?@,^calendar-notification@google\\.com$')
  .split(',').map(s => { try { return new RegExp(s, 'i'); } catch { return null; } }).filter(Boolean);

const EMAIL_RX = /([A-Z0-9._%+\-]+@[A-Z0-9.\-]+\.[A-Z]{2,})/i;

function parseAddress(raw) {
  if (!raw || typeof raw !== 'string') return null;
  const s = raw.trim(); if (!s) return null;
  const angle = s.match(/^(.*)<\s*([^>]+?)\s*>\s*$/);
  if (angle) {
    const name = angle[1].trim().replace(/^"|"$/g, '').trim() || null;
    const address = angle[2].trim().toLowerCase();
    if (!EMAIL_RX.test(address)) return null;
    return { name, address };
  }
  const m = s.match(EMAIL_RX);
  return m ? { name: null, address: m[1].toLowerCase() } : null;
}

function parseAddressList(val) {
  if (val == null) return [];
  if (Array.isArray(val)) return val.flatMap(parseAddressList);
  if (typeof val === 'object') {
    if (val.address) return [{ name: val.name || null, address: String(val.address).toLowerCase() }];
    if (val.value) return parseAddressList(val.value);
    return [];
  }
  if (typeof val !== 'string') return [];
  const out = []; let depth = 0, quoted = false, buf = '';
  for (let i = 0; i < val.length; i++) {
    const c = val[i];
    if (c === '"' && val[i-1] !== '\\') quoted = !quoted;
    else if (!quoted && c === '<') depth++;
    else if (!quoted && c === '>') depth--;
    if (c === ',' && !quoted && depth === 0) { if (buf.trim()) out.push(buf.trim()); buf = ''; }
    else buf += c;
  }
  if (buf.trim()) out.push(buf.trim());
  return out.map(parseAddress).filter(Boolean);
}

function isInternal(email) {
  if (!email) return false;
  const at = email.lastIndexOf('@'); if (at < 0) return false;
  return INTERNAL_DOMAINS.includes(email.slice(at+1).toLowerCase());
}

function isSkipSender(email) {
  return email && SKIP_SENDER_PATTERNS.some(rx => rx.test(email));
}

function isAutoresponderByHeaders(headers) {
  if (!headers) return false;
  const low = {}; for (const [k,v] of Object.entries(headers)) low[k.toLowerCase()] = Array.isArray(v) ? v.join(',') : v;
  for (const h of ['auto-submitted','x-autoreply','x-autorespond','x-auto-response-suppress']) {
    if (low[h] && String(low[h]).trim().toLowerCase() !== 'no') return true;
  }
  const p = (low['precedence'] || '').toLowerCase();
  return p.includes('bulk') || p.includes('auto_reply') || p.includes('auto-reply') || p.includes('junk');
}

const FWD_MARKERS = [
  /^-{3,}\s*Forwarded message\s*-{3,}/im,
  /^Begin forwarded message:/im,
  /^-{3,}\s*Original Message\s*-{3,}/im,
  /^From:\s.+\nSent:\s.+\nTo:\s.+/im,
];
function hasForwardMarker(body) { return body && FWD_MARKERS.some(rx => rx.test(body)); }

function parseForwardBlock(body) {
  if (!body) return null;
  let idx = -1;
  for (const rx of FWD_MARKERS) { const m = body.match(rx); if (m && m.index != null) { idx = m.index + m[0].length; break; } }
  if (idx < 0) return null;
  const tail = body.slice(idx).split(/\r?\n/).slice(0, 40).join('\n');
  const pick = (label) => { const m = tail.match(new RegExp(`^\\s*${label}\\s*:\\s*(.+)$`, 'im')); return m ? m[1].trim() : null; };
  const from = pick('From'), to = pick('To'), subject = pick('Subject'), date = pick('Date') || pick('Sent');
  if (!from && !to) return null;
  return { from, to, subject, date };
}

function htmlToText(html) {
  return String(html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, '').replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n\n').replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/\n{3,}/g, '\n\n').trim();
}

function firstExternal(list) {
  return list.find(a => a && a.address && a.address !== AUTOMATION_EMAIL && !isInternal(a.address)) || null;
}

function toIso(d) { if (!d) return null; try { const t = new Date(d); return isNaN(t.getTime()) ? null : t.toISOString(); } catch { return null; } }

function splitName(name) {
  if (!name) return { firstName: null, lastName: null };
  let n = String(name).trim().replace(/^"|"$/g, '').trim().replace(/^(dr|mr|mrs|ms|prof|rev|sr|jr)\.?\s+/i, '');
  if (!n) return { firstName: null, lastName: null };
  const parts = n.split(/\s+/);
  return parts.length === 1 ? { firstName: parts[0], lastName: null } : { firstName: parts[0], lastName: parts.slice(1).join(' ') };
}

const results = [];
for (const item of items) {
  const email = item.json;
  const headers = email.headers || email.payload?.headers || {};
  const hmap = {};
  if (Array.isArray(headers)) { for (const h of headers) hmap[String(h.name || '').toLowerCase()] = h.value; }
  else { for (const [k,v] of Object.entries(headers)) hmap[k.toLowerCase()] = v; }

  const from = parseAddressList(email.from || hmap['from'])[0] || null;
  const toList = parseAddressList(email.to || hmap['to']);
  const ccList = parseAddressList(email.cc || hmap['cc']);
  const body = (email.text && email.text.trim()) ? email.text : htmlToText(email.html);
  const subject = email.subject || hmap['subject'] || '';
  const messageId = email.messageId || hmap['message-id'] || null;
  const threadId = email.threadId || null;
  const originalTimestamp = toIso(email.date) || toIso(hmap['date']);

  const base = { type: 'skip', externalEmail: null, externalName: null, repEmail: from?.address || null,
    direction: null, subject, body, originalTimestamp, gmailMessageId: messageId, threadId, multiRecipient: false,
    firstName: null, lastName: null };

  if (from && (isSkipSender(from.address) || isAutoresponderByHeaders(hmap))) {
    results.push({ json: { ...base, skipReason: 'autoresponder' } }); continue;
  }

  const recipients = [...toList, ...ccList].filter(a => a.address !== AUTOMATION_EMAIL);
  const fromInternal = from && isInternal(from.address);

  if (fromInternal && recipients.length === 0 && hasForwardMarker(body)) {
    const inner = parseForwardBlock(body);
    if (!inner) { results.push({ json: { ...base, skipReason: 'unparseable' } }); continue; }
    const innerFrom = parseAddress(inner.from || '');
    const innerToList = parseAddressList(inner.to || '');
    const innerTs = toIso(inner.date) || originalTimestamp;

    if (innerFrom && !isInternal(innerFrom.address)) {
      const name = splitName(innerFrom.name);
      results.push({ json: { ...base, type: 'forward-inbound', direction: 'inbound',
        externalEmail: innerFrom.address, externalName: innerFrom.name, repEmail: from.address,
        subject: inner.subject || subject, originalTimestamp: innerTs,
        firstName: name.firstName, lastName: name.lastName } });
      continue;
    }
    const ext = firstExternal(innerToList);
    if (!ext) { results.push({ json: { ...base, skipReason: 'no-external-recipient' } }); continue; }
    const moreExt = innerToList.filter(a => a.address !== AUTOMATION_EMAIL && !isInternal(a.address)).length > 1;
    const name = splitName(ext.name);
    results.push({ json: { ...base, type: 'forward-outbound', direction: 'outbound',
      externalEmail: ext.address, externalName: ext.name,
      repEmail: (innerFrom && innerFrom.address) || from.address,
      subject: inner.subject || subject, originalTimestamp: innerTs, multiRecipient: moreExt,
      firstName: name.firstName, lastName: name.lastName } });
    continue;
  }

  if (fromInternal) {
    const ext = firstExternal(recipients);
    if (!ext) {
      if (recipients.length === 0) { results.push({ json: { ...base, skipReason: 'unparseable' } }); continue; }
      if (recipients.every(a => isInternal(a.address))) { results.push({ json: { ...base, skipReason: 'internal-only' } }); continue; }
      results.push({ json: { ...base, skipReason: 'no-external-recipient' } }); continue;
    }
    const externals = recipients.filter(a => !isInternal(a.address));
    const name = splitName(ext.name);
    results.push({ json: { ...base, type: 'bcc-outbound', direction: 'outbound',
      externalEmail: ext.address, externalName: ext.name, repEmail: from.address,
      multiRecipient: externals.length > 1, firstName: name.firstName, lastName: name.lastName } });
    continue;
  }

  results.push({ json: { ...base, skipReason: from ? 'no-external-recipient' : 'unparseable' } });
}
return results;

// Exact-match filter: the ?query= param matches name/email/phone, so we must
// confirm the returned contact actually has this email (case-insensitive).
const results = [];
for (const item of items) {
  const parse = item.json.__parse || item.json;        // fallback if not wrapped
  const search = item.json.search || item.json;
  const target = (parse.externalEmail || '').toLowerCase();
  const list = Array.isArray(search.contacts) ? search.contacts : [];
  const exact = list.find(c => {
    if (!c) return false;
    if (c.email && String(c.email).toLowerCase() === target) return true;
    if (Array.isArray(c.emails) && c.emails.some(e => { const v = typeof e === 'string' ? e : (e?.email || e?.value); return v && String(v).toLowerCase() === target; })) return true;
    return false;
  });
  results.push({ json: { ...parse, existingContactId: exact?.id || null, contactFound: !!exact } });
}
return results;

// Merge the created contact id onto the parsed payload and compute a
// deterministic idempotency key. Base64url of the tuple is sufficient —
// GHL just needs uniqueness + consistency per logical event, not crypto.
const results = [];
for (const item of items) {
  const parse = item.json.__parse || item.json;
  const created = item.json.created || item.json;
  const contactId = created?.contact?.id || created?.id;
  if (!contactId) {
    throw new Error(`createContact: response missing id. Body: ${JSON.stringify(created).slice(0, 400)}`);
  }
  const idempotencyKey = Buffer
    .from(`${parse.gmailMessageId || ''}|${contactId}|${parse.direction}`)
    .toString('base64url');
  results.push({ json: { ...parse, contactId, contactJustCreated: true, idempotencyKey } });
}
return results;
